from flask import Flask, request, jsonify
import face_recognition
import numpy as np
import os
import pickle

app = Flask(__name__)

# Directory containing employee photos
employee_photos_dir = 'employee_photos'
known_face_encodings = []
known_face_names = []

def load_employee_photos():
    for filename in os.listdir(employee_photos_dir):
        if filename.endswith('.jpg') or filename.endswith('.png'):
            image_path = os.path.join(employee_photos_dir, filename)
            employee_image = face_recognition.load_image_file(image_path)
            employee_encoding = face_recognition.face_encodings(employee_image)[0]
            known_face_encodings.append(employee_encoding)
            known_face_names.append(os.path.splitext(filename)[0])

load_employee_photos()

@app.route('/recognize', methods=['POST'])
def recognize():
    file = request.files['image']
    image = face_recognition.load_image_file(file)
    face_encodings = face_recognition.face_encodings(image)

    if len(face_encodings) == 0:
        return jsonify({"error": "No face found in the image"}), 400

    results = []
    for face_encoding in face_encodings:
        distances = face_recognition.face_distance(known_face_encodings, face_encoding)
        probabilities = 1 - distances
        results.append(probabilities)

    return jsonify({"confidence_scores": results, "names": known_face_names})

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)